/**
 * Deterministic voice post-fixes applied to every Telegram reply.
 *
 * Mirrors spark_character.output_sanitizer (Python) so the same rule
 * applies whether a reply was generated by the Node bot directly or
 * by the Python builder bridge. Currently scoped to the em-dash
 * family because production telemetry showed ~50% of replies leaked
 * em dashes despite the persona forbidding them, and prompt-layer
 * fixes were not enough.
 */

import { redactText } from './redaction';

const EM_DASH_FAMILY = [
  '\u2014', // em dash
  '\u2013', // en dash
  '\u2012', // figure dash
  '\u2015', // horizontal bar
  '\u2212', // minus sign
];

export function replaceEmDashes(text: string, replacement: string = ' - '): string {
  if (!text) return text;
  let out = text;
  for (const ch of EM_DASH_FAMILY) {
    out = out.split(ch).join(replacement);
  }
  while (out.indexOf('  ') !== -1) {
    out = out.split('  ').join(' ');
  }
  return out;
}

export function stripMarkdownEmphasis(text: string): string {
  if (!text) return text;
  return text
    .replace(/\*\*\*([^*\n][\s\S]*?[^*\n])\*\*\*/g, '$1')
    .replace(/\*\*([^*\n][\s\S]*?[^*\n])\*\*/g, '$1')
    .replace(/__([^_\n][\s\S]*?[^_\n])__/g, '$1');
}

export function sanitizeOutbound(text: string): string {
  return redactText(stripMarkdownEmphasis(replaceEmDashes(text)));
}
